#include<bits/stdc++.h>
using namespace std;struct V{double x,y,z;};struct T{int a,b,c;};double q(double x){return x*x;}V operator+(V a,V b){return{a.x+b.x,a.y+b.y,a.z+b.z};}V operator-(V a,V b){return{a.x-b.x,a.y-b.y,a.z-b.z};}V operator*(V a,double s){return{a.x*s,a.y*s,a.z*s};}double dot(V a,V b){return a.x*b.x+a.y*b.y+a.z*b.z;}V cross(V a,V b){return{a.y*b.z-a.z*b.y,a.z*b.x-a.x*b.z,a.x*b.y-a.y*b.x};}double norm(V a){return sqrt(dot(a,a));}V unit(V a){double n=norm(a);return n>1e-30?a*(1/n):V{0,0,1};}double val(V p,int k){return k==0?p.x:k==1?p.y:p.z;}double d2(V a,V b){return q(a.x-b.x)+q(a.y-b.y)+q(a.z-b.z);}void box(vector<V>&P){V lo{1e9,1e9,1e9},hi{-1e9,-1e9,-1e9};for(auto&p:P){lo.x=min(lo.x,p.x);lo.y=min(lo.y,p.y);lo.z=min(lo.z,p.z);hi.x=max(hi.x,p.x);hi.y=max(hi.y,p.y);hi.z=max(hi.z,p.z);}printf("8 12\n");for(int x=1;x>=0;x--)for(int y=1;y>=0;y--)for(int z=1;z>=0;z--)printf("v %.12g %.12g %.12g\n",x?hi.x:lo.x,y?hi.y:lo.y,z?hi.z:lo.z);int A[]={0,2,3,0,3,1,4,5,7,4,7,6,0,1,5,0,5,4,2,6,7,2,7,3,0,4,6,0,6,2,1,3,7,1,7,5};for(int i=0;i<12;i++)printf("f %d %d %d\n",A[3*i]+1,A[3*i+1]+1,A[3*i+2]+1);}void addor(vector<T>&F,vector<V>&W,int a,int b,int c,int ax,int sg){V n=cross(W[b]-W[a],W[c]-W[a]);double z=ax==0?n.x:ax==1?n.y:n.z;if(z*sg<0)swap(b,c);F.push_back({a,b,c});}int main(){ios::sync_with_stdio(false);cin.tie(nullptr);int N,M;if(!(cin>>N>>M))return 0;vector<V>P(N);string s;for(int i=0;i<N;i++)cin>>s>>P[i].x>>P[i].y>>P[i].z;for(int i=0,a,b,c;i<M;i++)cin>>s>>a>>b>>c;if(N<80){box(P);return 0;}V lo{1e9,1e9,1e9},hi{-1e9,-1e9,-1e9};for(auto&p:P){lo.x=min(lo.x,p.x);lo.y=min(lo.y,p.y);lo.z=min(lo.z,p.z);hi.x=max(hi.x,p.x);hi.y=max(hi.y,p.y);hi.z=max(hi.z,p.z);}double CL=sqrt(q(hi.x-lo.x)+q(hi.y-lo.y)+q(hi.z-lo.z)),E=.05*CL,of=.0045*CL;vector<int>R;vector<unsigned char>C(N);for(int i=0;i<N;i++)if(!C[i]){R.push_back(i);for(int j=i;j<N;j++)if(!C[j]&&sqrt(d2(P[i],P[j]))+2.5*of<=E)C[j]=1;if(R.size()*3+6*(10+1)*(10+1)>=N)break;}int G=10,H=G+1;vector<int>I(H*H*H,-1);vector<V>W;auto ID=[&](int x,int y,int z){return(x*H+y)*H+z;};auto addv=[&](int x,int y,int z,int ax,int sg){double t[3]={lo.x+(hi.x-lo.x)*x/G,lo.y+(hi.y-lo.y)*y/G,lo.z+(hi.z-lo.z)*z/G};int a1=(ax+1)%3,a2=(ax+2)%3,bi=0;double bs=1e100;for(int i=0;i<N;i++){double sc=q(val(P[i],a1)-t[a1])+q(val(P[i],a2)-t[a2])-.0015*sg*val(P[i],ax)*CL;if(sc<bs){bs=sc;bi=i;}}V p=P[bi];double jj=1e-7*CL*((int)W.size()%17-8);p.x+=jj*(x-G*.5);p.y+=jj*(y-G*.5);p.z+=jj*(z-G*.5);I[ID(x,y,z)]=W.size();W.push_back(p);};for(int x=0;x<=G;x++)for(int y=0;y<=G;y++)for(int z=0;z<=G;z++){int bd=(x==0||x==G)+(y==0||y==G)+(z==0||z==G);if(!bd)continue;int ax=0,sg=x?1:-1;if(x!=0&&x!=G){ax=1;sg=y?1:-1;if(y!=0&&y!=G){ax=2;sg=z?1:-1;}}addv(x,y,z,ax,sg);}vector<T>F;auto af=[&](int a,int b,int c,int ax,int sg){addor(F,W,a,b,c,ax,sg);};for(int s=0;s<2;s++){int x=s?G:0,sg=s?1:-1;for(int y=0;y<G;y++)for(int z=0;z<G;z++){int a=I[ID(x,y,z)],b=I[ID(x,y+1,z)],c=I[ID(x,y+1,z+1)],d=I[ID(x,y,z+1)];af(a,b,c,0,sg);af(a,c,d,0,sg);}}for(int s=0;s<2;s++){int y=s?G:0,sg=s?1:-1;for(int x=0;x<G;x++)for(int z=0;z<G;z++){int a=I[ID(x,y,z)],b=I[ID(x+1,y,z)],c=I[ID(x+1,y,z+1)],d=I[ID(x,y,z+1)];af(a,c,b,1,sg);af(a,d,c,1,sg);}}for(int s=0;s<2;s++){int z=s?G:0,sg=s?1:-1;for(int x=0;x<G;x++)for(int y=0;y<G;y++){int a=I[ID(x,y,z)],b=I[ID(x+1,y,z)],c=I[ID(x+1,y+1,z)],d=I[ID(x,y+1,z)];af(a,b,c,2,sg);af(a,c,d,2,sg);}}if(!F.empty()){int h=0;double ba=1e100;for(int i=0;i<(int)F.size();i++){V n=cross(W[F[i].b]-W[F[i].a],W[F[i].c]-W[F[i].a]);double aa=dot(n,n);if(aa<ba){ba=aa;h=i;}}T hole=F[h];F.erase(F.begin()+h);vector<array<int,3>>Rg;for(int id:R){V p=P[id],in=unit(V{-p.x,-p.y,-p.z}),u=fabs(in.x)<.8?unit(cross(in,V{1,0,0})):unit(cross(in,V{0,1,0})),v=cross(in,u),c=p+in*(of*.8);double r=of*.22;array<int,3>e;V A[3]={c+u*r,c+u*(-.5*r)+v*(.8660254*r),c+u*(-.5*r)+v*(-.8660254*r)};for(int k=0;k<3;k++){e[k]=W.size();W.push_back(A[k]);}Rg.push_back(e);}if(!Rg.empty()){int A[3]={hole.a,hole.b,hole.c};for(int i=0;i<3;i++){int a=A[i],b=A[(i+1)%3],c=Rg[0][(i+1)%3],d=Rg[0][i];F.push_back({a,b,c});F.push_back({a,c,d});}for(int k=0;k+1<(int)Rg.size();k++)for(int i=0;i<3;i++){int a=Rg[k][i],b=Rg[k][(i+1)%3],c=Rg[k+1][(i+1)%3],d=Rg[k+1][i];F.push_back({a,b,c});F.push_back({a,c,d});}auto L=Rg.back();F.push_back({L[0],L[1],L[2]});}}if(W.size()>100000||F.size()>200000){box(P);return 0;}printf("%d %d\n",(int)W.size(),(int)F.size());for(auto&p:W)printf("v %.12g %.12g %.12g\n",p.x,p.y,p.z);for(auto&t:F)printf("f %d %d %d\n",t.a+1,t.b+1,t.c+1);}